static uint64_t round_up_u64(uint64_t value, uint64_t align) {
    if (align <= 1u) return value;
    uint64_t rem = value % align;
    return rem == 0u ? value : value + (align - rem);
}

static void prefault_memory_region(void *ptr, uint64_t bytes) {
    if (!ptr || bytes == 0 || !CONFIG_MEMORY_PREFAULT) return;
    volatile uint8_t *cursor = (volatile uint8_t *)ptr;
    const uint64_t page_bytes = 4096u;
    for (uint64_t off = 0; off < bytes; off += page_bytes) {
        cursor[off] = 0;
    }
    cursor[bytes - 1u] = 0;
}

static void apply_memory_advice(void *ptr, uint64_t bytes, const char *name) {
    if (!ptr || bytes == 0) return;
#if defined(__linux__)
    int advice = 0;
    const uintptr_t page_bytes = 4096u;
    uintptr_t start = ((uintptr_t)ptr) & ~(page_bytes - 1u);
    uintptr_t end = round_up_u64((uint64_t)((uintptr_t)ptr + bytes), page_bytes);
    size_t advise_len = (size_t)(end - start);
    if (strcmp(CONFIG_MEMORY_ADVICE_STR, "random") == 0) {
#ifdef MADV_RANDOM
        advice = MADV_RANDOM;
#endif
    } else if (strcmp(CONFIG_MEMORY_ADVICE_STR, "sequential") == 0) {
#ifdef MADV_SEQUENTIAL
        advice = MADV_SEQUENTIAL;
#endif
    } else if (strcmp(CONFIG_MEMORY_ADVICE_STR, "hugepage") == 0) {
#ifdef MADV_HUGEPAGE
        advice = MADV_HUGEPAGE;
#endif
    } else if (strcmp(CONFIG_MEMORY_ADVICE_STR, "nohugepage") == 0) {
#ifdef MADV_NOHUGEPAGE
        advice = MADV_NOHUGEPAGE;
#endif
    }
    if (advice != 0) {
        int rc = madvise((void *)start, advise_len, advice);
        if (rc != 0) {
            fprintf(stderr, "[WARN] madvise failed for %s advice=%s start=0x%" PRIxPTR " len=%zu errno=%d\n", name, CONFIG_MEMORY_ADVICE_STR, start, advise_len, errno);
        }
    }
#else
    (void)name;
#endif
}

static bool ensure_memory_arena(void) {
    if (strcmp(CONFIG_MEMORY_ALLOCATOR_STR, "arena") != 0) return true;
    if (g_memory_arena_base != NULL) return true;
#if defined(__linux__)
    if (CONFIG_MEMORY_ARENA_BYTES == 0u) return true;
    void *hint = CONFIG_MEMORY_ARENA_HINT == 0u ? NULL : (void *)(uintptr_t)CONFIG_MEMORY_ARENA_HINT;
    void *base = mmap(hint, (size_t)CONFIG_MEMORY_ARENA_BYTES, PROT_READ | PROT_WRITE, MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (base == MAP_FAILED) {
        fprintf(stderr, "[ERROR] mmap arena failed bytes=%" PRIu64 " hint=0x%" PRIx64 " errno=%d\n", (uint64_t)CONFIG_MEMORY_ARENA_BYTES, (uint64_t)CONFIG_MEMORY_ARENA_HINT, errno);
        return false;
    }
    g_memory_arena_base = (uint8_t *)base;
    g_memory_arena_size = (uint64_t)CONFIG_MEMORY_ARENA_BYTES;
    g_memory_arena_cursor = 0u;
    return true;
#else
    fprintf(stderr, "[WARN] arena allocator requested but mmap arena is only implemented on linux; falling back to posix allocator\n");
    return true;
#endif
}

static bool allocate_memory_region(void **ptr, uint64_t bytes, size_t alignment, const char *name) {
    if (bytes == 0) return true;
    if (bytes > (uint64_t)((size_t)-1)) {
        fprintf(stderr, "[ERROR] %s bytes=%" PRIu64 " exceeds size_t max\n", name, bytes);
        return false;
    }
    *ptr = NULL;
    if (strcmp(CONFIG_MEMORY_ALLOCATOR_STR, "arena") == 0) {
        if (!ensure_memory_arena()) return false;
#if defined(__linux__)
        if (g_memory_arena_base != NULL) {
            uint64_t offset = round_up_u64(g_memory_arena_cursor, (uint64_t)alignment);
            if (offset + bytes > g_memory_arena_size) {
                fprintf(stderr, "[ERROR] arena overflow for %s need=%" PRIu64 " offset=%" PRIu64 " arena=%" PRIu64 "\n", name, bytes, offset, g_memory_arena_size);
                return false;
            }
            *ptr = (void *)(g_memory_arena_base + offset);
            g_memory_arena_cursor = offset + bytes + (uint64_t)CONFIG_MEMORY_ARENA_GAP_BYTES;
            apply_memory_advice(*ptr, bytes, name);
            prefault_memory_region(*ptr, bytes);
            return true;
        }
#endif
    }
    int rc = posix_memalign(ptr, alignment, (size_t)bytes);
    if (rc != 0 || *ptr == NULL) {
        fprintf(stderr, "[ERROR] failed to allocate %s bytes=%" PRIu64 " align=%zu rc=%d\n", name, bytes, alignment, rc);
        return false;
    }
    apply_memory_advice(*ptr, bytes, name);
    prefault_memory_region(*ptr, bytes);
    return true;
}

