typedef struct memory_region_info {
    const char *kind;
    const char *name;
    const void *base;
    uint64_t bytes;
    uint64_t pages;
    uint64_t nodes;
    uint64_t reps;
} memory_region_info_t;

typedef struct code_region_info {
    const char *kind;
    const char *name;
    const char *symbol;
    const void *entry;
    uint64_t payload_bytes;
    uint64_t cache_lines;
    uint64_t ldr_per_unit;
    uint64_t reps;
} code_region_info_t;

static int compare_memory_region_info(const void *lhs, const void *rhs) {
    const memory_region_info_t *left = (const memory_region_info_t *)lhs;
    const memory_region_info_t *right = (const memory_region_info_t *)rhs;
    uintptr_t left_addr = (uintptr_t)left->base;
    uintptr_t right_addr = (uintptr_t)right->base;
    return (left_addr > right_addr) - (left_addr < right_addr);
}

static int compare_code_region_info(const void *lhs, const void *rhs) {
    const code_region_info_t *left = (const code_region_info_t *)lhs;
    const code_region_info_t *right = (const code_region_info_t *)rhs;
    uintptr_t left_addr = (uintptr_t)left->entry;
    uintptr_t right_addr = (uintptr_t)right->entry;
    return (left_addr > right_addr) - (left_addr < right_addr);
}

static void print_memory_layout(uint64_t iters) {
    memory_region_info_t regions[] = {
        {"data", "data_stream", g_data_stream_buf, (uint64_t)(CONFIG_DATA_STREAM_SIZE), (uint64_t)(0), (uint64_t)(CONFIG_DATA_STREAM_ACCESSES_PER_CALL), (uint64_t)(CONFIG_DATA_STREAM_REGION_REPS)},
        {"data", "data_pointer_chase", g_data_pointer_chase_pool, (uint64_t)(CONFIG_DATA_POINTER_CHASE_POOL_BYTES), (uint64_t)(CONFIG_DATA_POINTER_CHASE_PAGE_COUNT), (uint64_t)(CONFIG_DATA_POINTER_CHASE_NODE_COUNT), (uint64_t)(CONFIG_DATA_POINTER_CHASE_REGION_REPS)},
        {"data", "data_page_stride", g_data_page_stride_buf, (uint64_t)(CONFIG_DATA_PAGE_STRIDE_POOL_BYTES), (uint64_t)(CONFIG_DATA_PAGE_STRIDE_PAGE_COUNT), (uint64_t)(CONFIG_DATA_PAGE_STRIDE_OFFSET_COUNT), (uint64_t)(CONFIG_DATA_PAGE_STRIDE_REGION_REPS)},
        {"data", "data_indirect_gather", g_data_indirect_gather_pool, (uint64_t)(CONFIG_DATA_INDIRECT_GATHER_POOL_BYTES), (uint64_t)(CONFIG_DATA_INDIRECT_GATHER_PAGE_COUNT), (uint64_t)(CONFIG_DATA_INDIRECT_GATHER_NODE_COUNT), (uint64_t)(CONFIG_DATA_INDIRECT_GATHER_REGION_REPS)},
        {"data", "data_hot_stride", g_data_hot_stride_buf, (uint64_t)(CONFIG_DATA_HOT_STRIDE_BUFFER_BYTES), (uint64_t)(0), (uint64_t)(CONFIG_DATA_HOT_STRIDE_ACCESS_COUNT), (uint64_t)(CONFIG_DATA_HOT_STRIDE_REGION_REPS)},
        {"data", "data_cold_stride", g_data_cold_stride_buf, (uint64_t)(CONFIG_DATA_COLD_STRIDE_BUFFER_BYTES), (uint64_t)(0), (uint64_t)(CONFIG_DATA_COLD_STRIDE_ACCESS_COUNT), (uint64_t)(CONFIG_DATA_COLD_STRIDE_REGION_REPS)},
        {"data", "data_tlb_indirect", g_data_tlb_indirect_buf, (uint64_t)(CONFIG_DATA_TLB_INDIRECT_POOL_BYTES), (uint64_t)(CONFIG_DATA_TLB_INDIRECT_PAGE_COUNT), (uint64_t)(CONFIG_DATA_TLB_INDIRECT_ACCESS_COUNT), (uint64_t)(CONFIG_DATA_TLB_INDIRECT_REGION_REPS)},
        {"attached-data", "hot_region_loop", g_hot_l1_attached_pool, (uint64_t)(CONFIG_HOT_L1_ATTACHED_POOL_BYTES), (uint64_t)(CONFIG_HOT_L1_ATTACHED_PAGE_COUNT), (uint64_t)(CONFIG_HOT_L1_ATTACHED_NODE_COUNT), (uint64_t)(CONFIG_HOT_L1_ATTACHED_REPS)},
        {"attached-data", "fetch_amplifier", g_fetch_attached_pool, (uint64_t)(CONFIG_FETCH_ATTACHED_POOL_BYTES), (uint64_t)(CONFIG_FETCH_ATTACHED_PAGE_COUNT), (uint64_t)(CONFIG_FETCH_ATTACHED_NODE_COUNT), (uint64_t)(CONFIG_FETCH_ATTACHED_REPS)},
        {"attached-data", "itlb", g_itlb_attached_pool, (uint64_t)(CONFIG_ITLB_ATTACHED_POOL_BYTES), (uint64_t)(CONFIG_ITLB_ATTACHED_PAGE_COUNT), (uint64_t)(CONFIG_ITLB_ATTACHED_NODE_COUNT), (uint64_t)(CONFIG_ITLB_ATTACHED_REPS)},
        {"attached-data", "cold_block_sequence", g_main_attached_pool, (uint64_t)(CONFIG_MAIN_ATTACHED_POOL_BYTES), (uint64_t)(CONFIG_MAIN_ATTACHED_PAGE_COUNT), (uint64_t)(CONFIG_MAIN_ATTACHED_NODE_COUNT), (uint64_t)(CONFIG_MAIN_ATTACHED_REPS)},
        {"mixed-data", "mixed_region_loop", g_mixed_region_pool, (uint64_t)(CONFIG_MIXED_REGION_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_REPS)},
        {"mixed-data", "mixed_region_loop_1", g_mixed_region_1_pool, (uint64_t)(CONFIG_MIXED_REGION_1_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_1_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_1_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_1_REPS)},
        {"mixed-data", "mixed_region_loop_2", g_mixed_region_2_pool, (uint64_t)(CONFIG_MIXED_REGION_2_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_2_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_2_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_2_REPS)},
        {"mixed-data", "mixed_region_loop_3", g_mixed_region_3_pool, (uint64_t)(CONFIG_MIXED_REGION_3_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_3_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_3_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_3_REPS)},
        {"mixed-data", "mixed_region_loop_4", g_mixed_region_4_pool, (uint64_t)(CONFIG_MIXED_REGION_4_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_4_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_4_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_4_REPS)},
        {"mixed-data", "mixed_region_loop_5", g_mixed_region_5_pool, (uint64_t)(CONFIG_MIXED_REGION_5_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_5_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_5_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_5_REPS)},
        {"mixed-data", "mixed_region_loop_6", g_mixed_region_6_pool, (uint64_t)(CONFIG_MIXED_REGION_6_POOL_BYTES), (uint64_t)(CONFIG_MIXED_REGION_6_PAGE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_6_NODE_COUNT), (uint64_t)(CONFIG_MIXED_REGION_6_REPS)},
    };
    code_region_info_t code_regions[] = {
        {"attached-code", "itlb", "itlb_attached_burst", (const void *)(uintptr_t)&itlb_attached_burst, (uint64_t)(CONFIG_ITLB_ATTACHED_INSTR_BYTES), (uint64_t)((CONFIG_ITLB_ATTACHED_INSTR_BYTES) / 64u), (uint64_t)(CONFIG_ITLB_ATTACHED_LDR_PER_UNIT), (uint64_t)(CONFIG_ITLB_ATTACHED_REPS)},
    };
    const size_t region_count = sizeof(regions) / sizeof(regions[0]);
    const size_t code_region_count = sizeof(code_regions) / sizeof(code_regions[0]);
    qsort(regions, region_count, sizeof(regions[0]), compare_memory_region_info);
    qsort(code_regions, code_region_count, sizeof(code_regions[0]), compare_code_region_info);
    uint64_t total_data_bytes = 0;
    size_t active_regions = 0;
    uintptr_t active_start = UINTPTR_MAX;
    uintptr_t active_end = 0u;
    for (size_t idx = 0; idx < region_count; ++idx) {
        if (regions[idx].bytes == 0 || regions[idx].reps == 0) continue;
        uintptr_t start = (uintptr_t)regions[idx].base;
        uintptr_t end = start + (uintptr_t)regions[idx].bytes;
        if (start < active_start) active_start = start;
        if (end > active_end) active_end = end;
        total_data_bytes += regions[idx].bytes;
        ++active_regions;
    }
    puts("===== memory layout =====");
    printf("iters=%" PRIu64 " active_data_regions=%zu total_data_bytes=%" PRIu64 " allocator=%s advice=%s arena_gap_bytes=%" PRIu64 " arena_bytes=%" PRIu64 " arena_hint=0x%" PRIx64 " prefault=%u warmup_iters=%" PRIu64 "\n",
           iters,
           active_regions,
           total_data_bytes,
           CONFIG_MEMORY_ALLOCATOR_STR,
           CONFIG_MEMORY_ADVICE_STR,
           (uint64_t)CONFIG_MEMORY_ARENA_GAP_BYTES,
           (uint64_t)CONFIG_MEMORY_ARENA_BYTES,
           (uint64_t)CONFIG_MEMORY_ARENA_HINT,
           (unsigned)CONFIG_MEMORY_PREFAULT,
           (uint64_t)CONFIG_WARMUP_ITERS);
    if (strcmp(CONFIG_MEMORY_ALLOCATOR_STR, "arena") == 0 && active_regions > 0 && active_start != UINTPTR_MAX) {
        printf("arena_span start=0x%" PRIxPTR " end=0x%" PRIxPTR " span_bytes=%" PRIu64 " mapped_bytes=%" PRIu64 "\n",
               active_start,
               active_end,
               (uint64_t)(active_end - active_start),
               (uint64_t)CONFIG_MEMORY_ARENA_BYTES);
    }
    for (size_t idx = 0; idx < region_count; ++idx) {
        if (regions[idx].bytes == 0 || regions[idx].reps == 0) continue;
        uintptr_t start = (uintptr_t)regions[idx].base;
        uintptr_t end = start + (uintptr_t)regions[idx].bytes;
        if (strcmp(CONFIG_MEMORY_ALLOCATOR_STR, "arena") == 0 && active_start != UINTPTR_MAX) {
            printf("data_region kind=%s name=%s start=0x%" PRIxPTR " end=0x%" PRIxPTR " bytes=%" PRIu64 " pages=%" PRIu64 " nodes=%" PRIu64 " reps=%" PRIu64 " arena_off=0x%" PRIxPTR "\n",
                   regions[idx].kind,
                   regions[idx].name,
                   start,
                   end,
                   regions[idx].bytes,
                   regions[idx].pages,
                   regions[idx].nodes,
                   regions[idx].reps,
                   (uintptr_t)(start - active_start));
        } else {
            printf("data_region kind=%s name=%s start=0x%" PRIxPTR " end=0x%" PRIxPTR " bytes=%" PRIu64 " pages=%" PRIu64 " nodes=%" PRIu64 " reps=%" PRIu64 "\n",
                   regions[idx].kind,
                   regions[idx].name,
                   start,
                   end,
                   regions[idx].bytes,
                   regions[idx].pages,
                   regions[idx].nodes,
                   regions[idx].reps);
        }
    }
    for (size_t idx = 0; idx < code_region_count; ++idx) {
        if (code_regions[idx].payload_bytes == 0) continue;
        uintptr_t entry = (uintptr_t)code_regions[idx].entry;
        uintptr_t approx_end = entry + (uintptr_t)code_regions[idx].payload_bytes;
        printf("code_region kind=%s name=%s symbol=%s entry=0x%" PRIxPTR " approx_payload_end=0x%" PRIxPTR " payload_bytes=%" PRIu64 " cache_lines=%" PRIu64 " ldr_per_unit=%" PRIu64 " reps=%" PRIu64 "\n",
               code_regions[idx].kind,
               code_regions[idx].name,
               code_regions[idx].symbol,
               entry,
               approx_end,
               code_regions[idx].payload_bytes,
               code_regions[idx].cache_lines,
               code_regions[idx].ldr_per_unit,
               code_regions[idx].reps);
    }
    fflush(stdout);
}

